form:Form.form:Scripts:
		function SetControls()
{
	Ctrl("l_automatica").SetXValue("1");
	EnableButtons();
}

function EnableButtons()
{       
	if (Ctrl("lblERROR").GetXValue()!="" || Ctrl('f_desde_solicitud').GetXValue() == "" || Ctrl('f_int').GetXValue() == ""  || Ctrl('e_dias_solicitud').GetXValue() == "")
	{
		CtrlEnabled("ACCEPT",false);
	} else
	{
		CtrlEnabled("ACCEPT",true);
	}

	if (Ctrl("l_automatica").GetXValue() == "1")
		CtrlEnabled("e_dias_solicitud",false);
	else
		CtrlEnabled("e_dias_solicitud",true);
}

function CALCULAR_DIAS()
{
	if (Ctrl('f_hasta_solicitud').GetXValue() < Ctrl('f_int').GetXValue())
	{
		alert("La Fecha de Interrupción tiene que se menor a la Fecha de Fin de las Vacaciones");
		Ctrl('f_int').SetXValue("");
		return false;
	}
	if (Ctrl('f_desde_solicitud').GetXValue() > Ctrl('f_int').GetXValue())
	{
		alert("La Fecha de Interrupción tiene que se mayor a la Fecha de Inicio de las Vacaciones");
		Ctrl('f_int').SetXValue("");
		return false;
	}

	if (Ctrl('l_automatica').GetXValue() == '1')
	{	
		if (Ctrl('f_desde_solicitud').GetXValue() == "" || Ctrl('f_int').GetXValue() == "")
		{
			Ctrl('e_dias_solicitud').SetXValue("");
			EnableButtons();
		} 
		else
			Ctrl('main').DoEvent('RECALCULAR_DIAS')
	}
}

