function val_fechas(MeCtrl)
{
	if (Ctrl('f_desde_solicitud').GetXValue()>Ctrl('f_int').GetXValue())
	{
		MeCtrl.SetError("La fecha de Interrupcion tiene que ser Mayor o Igual a la Fecha Desde.");
		return false;
	}
	if (Ctrl('f_hasta_solicitud').GetXValue()<=Ctrl('f_int').GetXValue())
	{
		MeCtrl.SetError("La fecha de Interrupcion tiene que ser Menor a la Fecha Hasta.");
		return false;
	}
	return true;
}

function ChgAuto()
{           
	Ctrl('f_int').SetXValue("");
	Ctrl('e_dias_solicitud').SetXValue("");

	EnableButtons();
}
